import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "" });

  // ✅ GET DOCTOR
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ✅ GET FEEDBACK
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  // ⭐ average rating
  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((sum, fb) => sum + fb.rating, 0) /
          feedbacks.length
        ).toFixed(1)
      : 0;

  // get weekday
  const getDayName = (dateStr) =>
    new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });

  // ✅ DATE CHECK
  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      setPopup({
        show: true,
        message: `Doctor not available on ${dayName}`,
      });
      setDate("");
      return;
    }

    setDate(selectedDate);
  };

  // ✅ BOOK BUTTON (IMPORTANT FIX HERE)
  const handleNext = async () => {
    if (!date || !time) {
      setPopup({
        show: true,
        message: "Please select date and time",
      });
      return;
    }

    const token = localStorage.getItem("token");
    if (!token) {
      navigate("/login");
      return;
    }

    try {
      const response = await fetch(
        "http://127.0.0.1:8000/book-appointment/",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Token ${token}`,
          },
          body: JSON.stringify({
            doctor_id: doctor_id,
            appointment_date: date,
            time_slot: time,
          }),
        }
      );

      const data = await response.json();

      if (response.ok) {
        setPopup({
          show: true,
          message: "Appointment booked successfully!",
        });

        setTimeout(() => {
          navigate("/myappointments");
        }, 1500);
      } else {
        setPopup({
          show: true,
          message: data.error || "Booking failed",
        });
      }
    } catch (error) {
      setPopup({
        show: true,
        message: "Server error. Try again later.",
      });
    }
  };

  // ⭐ FEEDBACK
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      setPopup({
        show: true,
        message: "Please add rating and comment",
      });
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  return (
    <div style={styles.container}>
      <Navbar />

      {/* POPUP */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <p>{popup.message}</p>
            <button
              style={styles.popupBtn}
              onClick={() => setPopup({ show: false, message: "" })}
            >
              OK
            </button>
          </div>
        </div>
      )}

      <div style={styles.main}>
        <div style={styles.card}>
          <div style={styles.left}>
            <img
              src={
                doctor.image ||
                "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt={doctor.name}
              style={styles.image}
            />
          </div>

          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience}</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>

            <div style={styles.bookingSection}>
              <input
                type="date"
                value={date}
                onChange={handleDateChange}
                style={styles.input}
              />

              <select
                value={time}
                onChange={(e) => setTime(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button style={styles.button} onClick={handleNext}>
                Book Appointment
              </button>
            </div>

            {/* FEEDBACK */}
            <div style={styles.reviewContainer}>
              <h3>Reviews ({avgRating} ⭐)</h3>

              <select
                value={rating}
                onChange={(e) => setRating(e.target.value)}
                style={styles.input}
              >
                <option value="">Rating</option>
                <option value="5">⭐⭐⭐⭐⭐</option>
                <option value="4">⭐⭐⭐⭐</option>
                <option value="3">⭐⭐⭐</option>
                <option value="2">⭐⭐</option>
                <option value="1">⭐</option>
              </select>

              <textarea
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                style={styles.textarea}
              />

              <button onClick={handleSubmitFeedback} style={styles.submitBtn}>
                Submit
              </button>
            </div>

          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* STYLES */
const styles = {
  container: { minHeight: "100vh", background: "#f4f6f9" },
  main: { display: "flex", justifyContent: "center", padding: "30px" },
  card: { display: "flex", background: "#fff", padding: "20px", borderRadius: "10px" },
  left: { marginRight: "20px" },
  image: { width: "150px", borderRadius: "50%" },

  input: { padding: "8px", margin: "5px", width: "100%" },
  textarea: { width: "100%", height: "80px" },

  button: { background: "#2c3e50", color: "#fff", padding: "10px" },
  submitBtn: { background: "green", color: "#fff", padding: "10px" },

  reviewContainer: { marginTop: "20px" },

  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    background: "rgba(0,0,0,0.5)",
    width: "100%",
    height: "100%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  popupCard: {
    background: "#fff",
    padding: "20px",
    borderRadius: "10px",
  },

  popupBtn: {
    marginTop: "10px",
    padding: "5px 15px",
  },

  loading: { textAlign: "center", marginTop: "50px" },
};
